function paymentsPage(){return `${head('支付方式','管理记账时可选择的余额账户和月付方式')}<section class="panel"><div class="panel-title"><span>💳 支付平台 / 入账账户</span><span>拖动手柄可调整顺序</span></div><div class="panel-body"><form id="accountsForm"><div class="account-list" id="platformList">${state.platforms.map(p=>`<div class="account manage-row sortable-row" data-sort-platform="${escapeHtml(p.name)}"><span class="manage-name"><span class="drag-handle" title="拖动排序">☰</span><input data-platform-name="${escapeHtml(p.name)}" value="${escapeHtml(p.name)}" maxlength="16" aria-label="支付方式名称"></span><select data-platform-kind="${escapeHtml(p.name)}" aria-label="${escapeHtml(p.name)}类型"><option value="account" ${p.kind==='account'?'selected':''}>余额账户</option><option value="credit" ${p.kind==='credit'?'selected':''}>月付方式</option></select>${p.kind==='account'?`<span class="balance-input"><span>¥</span><input data-account="${escapeHtml(p.name)}" aria-label="${escapeHtml(p.name)}余额" type="number" step="0.01" value="${Number(state.accounts[p.name]||0).toFixed(2)}" required></span>`:'<span class="status-pill">消费后待还款</span>'}<button type="button" class="icon-button danger-icon" data-remove-platform="${escapeHtml(p.name)}" title="删除支付方式">×</button></div>`).join('')}</div><div class="inline-add"><input id="newPlatform" maxlength="16" placeholder="新支付方式名称"><select id="newPlatformKind"><option value="account">余额账户</option><option value="credit">月付方式</option></select><button type="button" class="secondary" id="addPlatform">＋ 添加</button></div><div class="notice" style="margin-top:14px">💡 余额账户会随收支、还款和存款转账增减；月付消费会进入待还款。</div><div class="form-actions"><button type="button" class="hidden" id="depositSavings"></button><button type="button" class="hidden" id="withdrawSavings"></button><button class="primary">保存支付方式</button></div></form></div></section>`}

function rememberedLogin(){try{let value=JSON.parse(localStorage.getItem(REMEMBER_LOGIN_KEY)||'null');return value?.email&&value?.password?value:null}catch{return null}}
function login(){let isLogin=authMode==='login',remembered=isLogin?rememberedLogin():null;app.innerHTML=`<div class="login-shell"><div class="window login"><div class="titlebar"><span>🔐 ${isLogin?'登录':'注册'}小金库</span><div class="traffic"><span>─</span><span>□</span><span class="close">×</span></div></div><form class="login-welcome" id="authForm"><div class="avatar">🐷</div><h1>小金库</h1><p>${isLogin?'登录后在 Mac 和 iPhone 同步账本':'创建你的私人云端账本'}</p><div class="field" style="text-align:left;margin-top:22px"><label for="email">邮箱</label><input id="email" type="email" autocomplete="email" value="${escapeHtml(remembered?.email||'')}" placeholder="name@example.com" required><label for="password">密码</label><input id="password" type="password" minlength="6" autocomplete="${isLogin?'current-password':'new-password'}" value="${escapeHtml(remembered?.password||'')}" placeholder="至少 6 位密码" required></div>${isLogin?`<label class="remember-login"><input id="rememberLogin" type="checkbox" ${remembered?'checked':''}><span><b>记住用户名和密码</b><small>仅建议在自己的私人设备上使用</small></span></label>`:''}<div id="authMessage" class="auth-message hidden"></div><button class="primary" id="loginBtn" style="width:100%;margin-top:18px;padding:10px">${isLogin?'登录':'免费注册'}</button>${isLogin?'<button type="button" class="secondary" id="demoBtn" style="width:100%;margin-top:9px">免登录进入演示</button>':''}<button type="button" class="link-button" id="switchAuth">${isLogin?'第一次使用？创建账号':'已有账号？返回登录'}</button></form></div></div>`;document.querySelector('#switchAuth').onclick=()=>{authMode=isLogin?'register':'login';login()};document.querySelector('#demoBtn')?.addEventListener('click',()=>{demoMode=true;syncStatus='演示模式';state=structuredClone(demoState);logged=true;render()});document.querySelector('#authForm').onsubmit=handleAuth}
async function handleAuth(e){e.preventDefault();let email=document.querySelector('#email').value.trim(),password=document.querySelector('#password').value,remember=document.querySelector('#rememberLogin')?.checked,button=document.querySelector('#loginBtn'),box=document.querySelector('#authMessage');button.disabled=true;button.textContent=authMode==='login'?'正在登录…':'正在注册…';box.classList.add('hidden');try{if(authMode==='login'){let data=await api('/auth/v1/token?grant_type=password',{method:'POST',body:JSON.stringify({email,password})});if(remember)localStorage.setItem(REMEMBER_LOGIN_KEY,JSON.stringify({email,password}));else localStorage.removeItem(REMEMBER_LOGIN_KEY);session={...data,expires_at:Math.floor(Date.now()/1000)+data.expires_in};localStorage.setItem(SESSION_KEY,JSON.stringify(session));logged=true;await pullCloud();render();toast('登录成功，账本已同步 ✓')}else{let data=await api('/auth/v1/signup',{method:'POST',body:JSON.stringify({email,password})});if(data?.access_token){session={...data,expires_at:Math.floor(Date.now()/1000)+data.expires_in};localStorage.setItem(SESSION_KEY,JSON.stringify(session));logged=true;await pullCloud();render();toast('账号创建成功 ✓')}else{box.textContent='注册成功！请打开邮箱中的验证邮件，然后回来登录。';box.classList.remove('hidden');authMode='login';button.textContent='返回登录';button.onclick=()=>login()}}}catch(err){box.textContent=friendlyError(err);box.classList.remove('hidden');button.disabled=false;button.textContent=authMode==='login'?'登录':'免费注册'}}

function escapeHtml(s=''){return String(s).replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]))}
const importKeywords=[
  {category:'打车',words:['滴滴','曹操出行','T3出行','出租车','网约车','代驾']},
  {category:'用车',words:['加油站','中国石油','中国石化','充电桩','停车','高速公路','ETC','通行费','洗车','汽车服务','共享单车','先骑后付','骑行']},
  {category:'咖啡',words:['咖啡','coffee','星巴克','瑞幸','库迪','MANNER']},
  {category:'吃饭',words:['餐饮','餐厅','饭店','外卖','美团','饿了么','奶茶','茶饮','肯德基','麦当劳','便利店','超市']},
  {category:'衣物',words:['服饰','服装','鞋','优衣库','女装','男装']},
  {category:'化妆品',words:['美妆','化妆','护肤','屈臣氏','丝芙兰']},
  {category:'娱乐',words:['电影','影院','游戏','视频会员','音乐会员','会员','KTV','游乐','健身']},
  {category:'医疗',words:['医院','药房','药店','诊所','医疗','健康']},
  {category:'礼物',words:['礼品','鲜花','花店','蛋糕']}
]
function importCategory(merchant,product){let remembered=state.importCategoryRules?.[merchant];if(remembered&&state.categories.includes(remembered))return remembered;let text=`${merchant} ${product}`.toLowerCase();for(let rule of importKeywords){if(state.categories.includes(rule.category)&&rule.words.some(word=>text.includes(word.toLowerCase())))return rule.category}return state.categories.includes('其他')?'其他':state.categories[0]}
