function confirmBillImport(){let selected=importPreview?.items.filter(item=>item.selected)||[];if(!selected.length)return;state.importCategoryRules||={};if(document.querySelector('#rememberImportRules')?.checked)selected.filter(item=>item.type==='expense'&&item.category!==item.suggestedCategory&&item.merchant).forEach(item=>state.importCategoryRules[item.merchant]=item.category);let source=importPreview.source||'wechat',provider=importPreview.provider||'微信',platform=importPreview.platform||'微信',batchId=`${source}-${Date.now()}`,importedAt=new Date().toISOString(),baseId=Date.now();selected.forEach((item,index)=>state.transactions.unshift({id:baseId+index,type:item.type,amount:item.amount,category:item.type==='income'?'收入':item.category,platform,date:item.date,time:item.time,note:item.note,repaid:true,affectsBalance:false,source,sourceId:item.sourceId,importBatchId:batchId,importedAt}));let count=selected.length;importPreview=null;save();page='records';recordsMonth=null;recordsType='all';recordsCategory='all';render();toast(`已导入 ${count} 笔，${provider}余额未修改 ✓`)}
function openImportCategoryDialog(index){let item=importPreview?.items[index];if(!item)return;document.body.insertAdjacentHTML('beforeend',`<div class="modal-wrap import-category-dialog"><div class="modal"><div class="titlebar"><span>＋ 新增消费分类</span><div class="traffic"><button type="button" class="close" data-close-import-category aria-label="关闭">×</button></div></div><div class="body"><form id="importCategoryForm"><div class="form-grid"><div class="field"><label for="importCategoryIcon">图标</label><input id="importCategoryIcon" maxlength="8" value="📁" required></div><div class="field"><label for="importCategoryName">分类名称</label><input id="importCategoryName" maxlength="12" placeholder="例如：日用品" required></div><div class="field full"><label for="importCategoryBudget">每月预算（可选）</label><input id="importCategoryBudget" type="number" min="0" step="1" value="0"></div></div><div class="form-actions"><button type="button" class="secondary" data-close-import-category>取消</button><button class="primary">保存并选中</button></div></form></div></div></div>`);let dialog=document.querySelector('.import-category-dialog'),close=()=>dialog?.remove();dialog.querySelectorAll('[data-close-import-category]').forEach(button=>button.onclick=close);dialog.querySelector('#importCategoryForm').onsubmit=e=>{e.preventDefault();let name=dialog.querySelector('#importCategoryName').value.trim(),icon=dialog.querySelector('#importCategoryIcon').value.trim(),budget=Number(dialog.querySelector('#importCategoryBudget').value||0);if(!name){toast('请输入分类名称');return}if(state.categories.includes(name)){toast('分类名称已存在，请直接选择');return}if(!icon){toast('请输入分类图标');return}if(!Number.isFinite(budget)||budget<0){toast('请输入正确的预算金额');return}state.categories.push(name);state.budgets[name]=budget;state.categoryIcons[name]=icon;item.category=name;save();close();render();toast(`已新增“${name}”并选中 ✓`)}}
function updateImportSelectionUi(){if(!importPreview)return;let selected=importPreview.items.filter(item=>item.selected),incomeCount=selected.filter(item=>item.type==='income').length,expenseCount=selected.filter(item=>item.type==='expense').length,title=document.querySelector('.import-preview>.panel-title>span'),confirm=document.querySelector('#confirmBillImport'),selectAll=document.querySelector('#importSelectAll');if(title)title.textContent=`🧾 已选 ${selected.length} 笔 · 收入 ${incomeCount} 笔 · 支出 ${expenseCount} 笔`;if(confirm){confirm.textContent=`确认导入 ${selected.length} 笔`;confirm.disabled=!selected.length}if(selectAll)selectAll.checked=!!importPreview.items.length&&selected.length===importPreview.items.length}
function avatarHtml(cls='avatar'){return state.profile.avatar?`<div class="${cls}"><img src="${state.profile.avatar}" alt="${escapeHtml(state.profile.name)}的头像"></div>`:`<div class="${cls}">🐷</div>`}
function classicToolbar(){return `<div class="classic-toolbar" aria-label="快捷工具栏"><span class="disabled-tool"><b>📄</b>新建</span><button type="button" data-page="add"><b>📝</b>记一笔</button><span class="disabled-tool"><b>✎</b>编辑</span><span class="disabled-tool"><b>❌</b>删除</span><button type="button" data-page="import"><b>📥</b>导入</button><button type="button" id="exportLedger"><b>📤</b>导出</button><button type="button" data-page="stats"><b>📊</b>报表</button><span class="disabled-tool"><b>💾</b>备份</span><button type="button" data-page="my"><b>⚙</b>设置</button><span class="disabled-tool"><b>❓</b>帮助</span></div>`}
function shell(){return `<div class="desktop"><div class="topbar"><div class="brand"><span class="brand-icon">🐷</span>小金库 2003</div><div class="today">今天是 2026年7月21日 · ${now()}</div></div><section class="window"><div class="titlebar"><span>📒 我的账本 - 小金库</span><div class="traffic"><button id="refreshPage" title="刷新当前页面" aria-label="刷新当前页面">↻</button><span>─</span><span>□</span><span class="close">×</span></div></div><div class="menu" aria-label="应用菜单"><span>文件(F)</span><span>编辑(E)</span><span>查看(V)</span><span>帮助(H)</span></div>${classicToolbar()}<div class="workspace"><aside class="sidebar"><div class="user-card">${avatarHtml()}<b>${escapeHtml(state.profile.name)}</b><small data-sync>在线 · ${syncStatus}</small></div><div class="nav">${navButtons()}</div><div class="side-tip">💡 本月提醒<br>先记账，再消费。你的每一笔月付都已经计入当月支出。</div></aside><main class="main page-${page}">${content()}</main></div></section></div><footer class="taskbar"><button class="start">⊞ 开始</button><div class="task-tab">📒 小金库</div><div class="mobile-nav">${mobileNav()}</div><div class="clock">${now()}</div></footer>${modal?modalHtml():''}`}
function navButtons(){return [['home','🏠','首页'],['add','➕','记一笔'],['records','📋','明细'],['stats','📈','统计'],['debts','⏰','待还款'],['budget','📊','预算'],['accounts','💳','账户'],['my','⚙','设置']].map(x=>`<button data-page="${x[0]}" class="${page===x[0]||page==='profile'&&x[0]==='my'?'active':''}"><span>${x[1]}</span>${x[2]}</button>`).join('')+`<button id="logout"><span>🚪</span>退出登录</button>`}
function mobileNav(){return [['home','🏠','首页'],['records','📋','明细'],['add','✏️','记账'],['stats','📈','统计'],['debts','⏰','还款'],['my','⚙️','设置']].map(x=>`<button data-page="${x[0]}" class="${page===x[0]||page==='profile'&&x[0]==='my'?'active':''}"><span>${x[1]}</span>${x[2]}</button>`).join('')}
const secondaryPages=new Set(['import','budget','accounts','profile'])
function navigateTo(target){if(!target||target===page)return;pageHistory.push(page);if(pageHistory.length>20)pageHistory.shift();page=target;render()}
function navigateBack(){page=pageHistory.pop()||(page==='profile'?'my':'home');render()}
function head(title,sub,action=''){if(page==='accounts'&&title==='支付方式'){title='账户';sub='管理账户余额、支付平台和月付方式'}let back=secondaryPages.has(page)?'<button type="button" class="page-back" id="pageBack" aria-label="返回上一个页面">← <span>返回</span></button>':'';return `<div class="page-head"><div class="page-head-main">${back}<div><h1>${title}</h1><p>${sub}</p></div></div>${action}</div>`}
function content(){if(page==='add')return addPage();if(page==='import')return importPage();if(page==='records')return recordsPage();if(page==='stats')return statsPage();if(page==='debts')return debtsPage();if(page==='budget')return budgetPage();if(page==='accounts')return paymentsPage();if(page==='my'||page==='settings')return settingsPage();if(page==='profile')return profilePage();return homePage()}
function homePage(){const d=debt().reduce((s,t)=>s+t.amount,0),previous=cycleFinance(previousCycleMonth()),filterButton=(type,label)=>`<button type="button" class="card-filter-button" data-page="records" data-records-filter="${type}" title="${label}" aria-label="${label}">›</button>`;return `${head(`下午好，${escapeHtml(state.profile.name)} 👋`,'今天也要照顾好自己的钱包','<button class="primary" data-page="add">＋ 记一笔</button>')}<div class="section-heading account-overview-heading"><div><h2>账户总览</h2><p>余额、存款与当前记账周期 · ${cycleLabel(currentCycleMonth())}</p></div></div><div class="cards dashboard-cards"><div class="card dashboard-card income-card"><div class="card-heading"><b>本周期收入</b>${filterButton('income','查看本周期收入明细')}</div><div class="card-value"><span class="metric-icon"><i class="icon-v1">💵</i><i class="icon-v2">💰</i></span><div class="money">${money(income())}</div></div>${monthTrend(income(),previous.income,true)}</div><div class="card dashboard-card orange expense-card"><div class="card-heading"><b>本周期花销</b>${filterButton('expense','查看本周期花销明细')}</div><div class="card-value"><span class="metric-icon"><i class="icon-v1">🧾</i><i class="icon-v2">🛒</i></span><div class="money">${money(expense())}</div></div>${monthTrend(expense(),previous.expense,false)}</div><div class="card dashboard-card ${remainingBudget()<0?'red':'green'} budget-card"><div class="card-heading"><b>本周期剩余预算</b></div><div class="card-value"><span class="metric-icon"><i class="icon-v1">🎯</i><i class="icon-v2">📊</i></span><div class="money">${money(remainingBudget())}</div></div><span class="sub">预算总额：${money(totalBudget())}</span></div><div class="card dashboard-card red debt-card"><div class="card-heading"><b>待还款</b>${filterButton('debt','查看本周期待还款明细')}</div><div class="card-value"><span class="metric-icon"><i class="icon-v1">⏳</i><i class="icon-v2">💳</i></span><div class="money">${money(d)}</div></div><span class="sub">待还款笔数：${debt().length} 笔</span></div></div>${accountOverview()}<div class="grid2"><section class="panel"><div class="panel-title"><span>📊 类别预算 · 共 ${state.categories.length} 类</span><button class="secondary" data-page="budget">管理预算</button></div><div class="panel-body home-scroll-body">${state.categories.map(budgetLine).join('')}</div></section><section class="panel"><div class="panel-title"><span>📝 明细 · 共 ${state.transactions.length} 笔</span><button class="secondary" data-page="records">查看全部</button></div><div class="panel-body home-scroll-body">${sortedTransactions(state.transactions).map(txLine).join('')||'<div class="empty">还没有收支记录</div>'}</div></section></div>`}
function budgetLine(c){let u=used(c),b=Number(state.budgets[c]),left=b-u,p=Math.min(100,u/b*100||0);return `<div class="budget-row"><div class="row-top"><span>${categoryIcon(c)} ${escapeHtml(c)}</span><span class="${left<0?'budget-over':''}">剩余 ${money(left)}</span></div><div class="track"><div class="fill ${p>80?'warn':''}" style="width:${p}%"></div></div><div class="budget-meta">已用 ${money(u)} / 预算 ${money(b)}</div></div>`}
function txLine(t,actions=false){return `<div class="tx ${actions?'tx-manage':''}"><span class="tx-icon">${t.type==='income'?'💰':categoryIcon(t.category)}</span><span><b>${escapeHtml(t.note||t.category)}</b><small>${t.date.slice(5)} ${t.time} · ${escapeHtml(t.platform)}${!t.repaid?' · 待还款':''}</small></span><span class="tx-amount ${t.type==='income'?'in':''}">${t.type==='income'?'+':'−'}${money(t.amount)}</span>${actions?`<span class="tx-actions"><button class="icon-button" data-edit-tx="${t.id}" title="编辑记录">✎</button><button class="icon-button danger-icon" data-delete-tx="${t.id}" title="删除记录">×</button></span>`:''}</div>`}
function platformButtons(kind){return state.platforms.filter(p=>p.kind===kind).map((p,i)=>`<button type="button" data-value="${escapeHtml(p.name)}" class="${i===0?'selected':''}">${escapeHtml(p.name)}</button>`).join('')}
function addPage(){let hasCredit=creditPlatforms().length>0,addButton=target=>`<button type="button" class="primary field-add-button" data-page="${target}">增加＋</button>`;return `${head('记一笔','日期与时间会自动填充')}<section class="panel add-panel"><div class="panel-title">✏️ 新增记录</div><div class="panel-body"><form id="txForm"><div class="choice" id="typeChoice"><button type="button" class="selected" data-value="expense">花销</button><button type="button" data-value="income">收入</button></div><div class="form-grid" style="margin-top:14px"><div class="field full"><label>金额</label><input class="amount-input" id="amount" type="number" min="0.01" step="0.01" placeholder="¥ 0.00" required></div><div class="field full" id="catField"><div class="field-label-row"><label>类别</label>${addButton('budget')}</div><div class="choice" id="catChoice">${state.categories.map((c,i)=>`<button type="button" data-value="${escapeHtml(c)}" class="${i===0?'selected':''}">${categoryIcon(c)} ${escapeHtml(c)}</button>`).join('')}</div></div><div class="field date-field"><label>日期</label><input id="date" type="date" value="${today()}"></div><div class="field time-field"><label>时间</label><input id="time" type="time" value="${new Date().toTimeString().slice(0,5)}"></div><div class="field full" id="payModeField"><div class="field-label-row"><label>付款方式</label>${addButton('accounts')}</div><div class="choice segmented" id="payModeChoice"><button type="button" data-value="account" class="selected">余额支付</button><button type="button" data-value="credit" ${hasCredit?'':'disabled'}>月付</button></div></div><div class="field full" id="accountPlatformField"><div class="field-label-row"><label id="accountPlatformLabel">支付平台</label>${addButton('accounts')}</div><div class="choice" id="accountPlatformChoice">${platformButtons('account')}</div></div><div class="field full hidden" id="creditPlatformField"><div class="field-label-row"><label>选择月付平台</label>${addButton('accounts')}</div><div class="choice" id="creditPlatformChoice">${platformButtons('credit')}</div></div><div class="field full"><label>备注</label><textarea id="note" rows="2" placeholder="写点什么（可选）"></textarea></div></div><div class="form-actions"><button type="button" class="primary" id="saveTransaction">保存记录</button></div></form></div></section>`}
function recordsPage(){let selected=recordsMonth||currentCycleMonth(),categories=[...new Set([...state.categories,...state.transactions.filter(t=>t.type==='expense').map(t=>t.category)])],list=state.transactions.filter(t=>inCycle(t.date,selected));if(recordsType==='income')list=list.filter(t=>t.type==='income');if(recordsType==='expense')list=list.filter(t=>t.type==='expense');if(recordsType==='debt')list=list.filter(t=>t.type==='expense'&&!t.repaid&&platformKind(t.platform)==='credit');if(recordsCategory!=='all')list=list.filter(t=>t.category===recordsCategory);list=sortedTransactions(list);return `${head('收支明细','按记账周期、类型和类别筛选所需记录','<button class="primary" data-page="add">＋ 记一笔</button>')}<form class="filter-bar records-filter-bar" id="recordsFilterForm"><label>周期起始月<input id="recordsMonth" type="month" value="${selected}" required></label><label>类型<select id="recordsType"><option value="all" ${recordsType==='all'?'selected':''}>全部</option><option value="expense" ${recordsType==='expense'?'selected':''}>支出</option><option value="income" ${recordsType==='income'?'selected':''}>收入</option><option value="debt" ${recordsType==='debt'?'selected':''}>待还款</option></select></label><label>类别<select id="recordsCategory"><option value="all">全部类别</option>${categories.map(c=>`<option value="${escapeHtml(c)}" ${recordsCategory===c?'selected':''}>${categoryIcon(c)} ${escapeHtml(c)}</option>`).join('')}</select></label><button class="primary" id="applyRecordsFilter">筛选</button><span>共 ${list.length} 笔</span></form><section class="panel"><div class="panel-title"><span>📋 ${cycleLabel(selected)}</span><span>收入 ${money(list.filter(t=>t.type==='income').reduce((s,t)=>s+t.amount,0))} · 支出 ${money(list.filter(t=>t.type==='expense').reduce((s,t)=>s+t.amount,0))}</span></div><div class="panel-body">${list.length?list.map(t=>txLine(t,true)).join(''):'<div class="empty">没有符合筛选条件的记录</div>'}</div></section>`}
function statsPage(){let list=statsTransactions(),incomeTotal=list.filter(t=>t.type==='income').reduce((s,t)=>s+Number(t.amount),0),expenseTotal=list.filter(t=>t.type==='expense').reduce((s,t)=>s+Number(t.amount),0),maxTotal=Math.max(incomeTotal,expenseTotal,1),groups={};list.filter(t=>t.type==='expense').forEach(t=>groups[t.category]=(groups[t.category]||0)+Number(t.amount));let parts=Object.entries(groups).sort((a,b)=>b[1]-a[1]),cursor=0,gradient=parts.length?parts.map(([c,v],i)=>{let start=cursor;cursor+=v/expenseTotal*100;return `${statsColors[i%statsColors.length]} ${start}% ${cursor}%`}).join(','):'#e1dfd3 0 100%',available=state.categories.filter(category=>category in groups);statsCategories=statsCategories===null?available.slice(0,3):statsCategories.filter(category=>state.categories.includes(category)).slice(0,3);let categoryColors=Object.fromEntries(state.categories.map((category,index)=>[category,statsColors[index%statsColors.length]]));return `${head('收支统计','按记账周期、按年或自定义时间查看财务情况')}<section class="panel stats-filter"><div class="panel-body"><div class="choice segmented" id="statsMode"><button data-value="month" class="${statsMode==='month'?'selected':''}">按周期</button><button data-value="year" class="${statsMode==='year'?'selected':''}">按年</button><button data-value="custom" class="${statsMode==='custom'?'selected':''}">自定义</button></div><div class="stats-date-controls"><label class="${statsMode==='month'?'':'hidden'}">周期起始月<input id="statsMonth" type="month" value="${statsMonth||currentCycleMonth()}"></label><label class="${statsMode==='year'?'':'hidden'}">年份<input id="statsYear" type="number" min="2000" max="2100" value="${statsYear||today().slice(0,4)}"></label><label class="${statsMode==='custom'?'':'hidden'}">开始<input id="statsStart" type="date" value="${statsStart||`${currentMonth()}-01`}"></label><label class="${statsMode==='custom'?'':'hidden'}">结束<input id="statsEnd" type="date" value="${statsEnd||today()}"></label></div></div></section><div class="cards stats-summary"><div class="card green"><span class="label">${statsPeriodLabel()}收入</span><div class="money">${money(incomeTotal)}</div></div><div class="card orange"><span class="label">支出</span><div class="money">${money(expenseTotal)}</div></div><div class="card ${incomeTotal-expenseTotal<0?'red':'green'}"><span class="label">结余</span><div class="money">${money(incomeTotal-expenseTotal)}</div></div><div class="card"><span class="label">记录数量</span><div class="money">${list.length}</div></div></div>${statsTrendHtml(list,statsCategories,categoryColors)}<div class="stats-grid"><section class="panel"><div class="panel-title">📊 收支对比</div><div class="panel-body"><div class="bar-chart"><div class="bar-item"><div class="bar-value">${money(incomeTotal)}</div><div class="bar-column income-bar" style="height:${Math.max(6,incomeTotal/maxTotal*100)}%"></div><b>收入</b></div><div class="bar-item"><div class="bar-value">${money(expenseTotal)}</div><div class="bar-column expense-bar" style="height:${Math.max(6,expenseTotal/maxTotal*100)}%"></div><b>支出</b></div></div></div></section><section class="panel"><div class="panel-title">🍰 支出类别</div><div class="panel-body pie-layout"><div class="pie" style="background:conic-gradient(${gradient})"><span>${expenseTotal?money(expenseTotal):'暂无支出'}</span></div><div class="pie-legend">${parts.length?parts.map(([c,v],i)=>`<div><i style="background:${statsColors[i%statsColors.length]}"></i><span>${categoryIcon(c)} ${escapeHtml(c)}</span><b>${money(v)} · ${(v/expenseTotal*100).toFixed(1)}%</b></div>`).join(''):'<div class="empty">所选时间暂无支出</div>'}</div></div></section></div>`}
function debtsPage(){let groups=creditPlatforms().map(p=>p.name),next=nextRepayment();return `${head('待还款','还款只扣账户余额，不会重复计入花销')}<div class="notice">🔔 <span><b>下次还款日：${repaymentDateLabel(next.date)}</b><br>还有 ${next.days} 天 · 每月 ${state.profile.repaymentReminderDay} 号提醒</span></div><div style="height:14px"></div>${groups.map(g=>{let list=debt().filter(t=>t.platform===g),sum=list.reduce((s,t)=>s+t.amount,0),allSelected=list.length&&list.every(t=>selectedDebt.has(t.id));return `<section class="panel debt-group"><div class="debt-head"><b>${escapeHtml(g)}</b><span><b>${money(sum)}</b>${list.length?`<button type="button" data-select-debt-group="${escapeHtml(g)}">${allSelected?'取消全选':'全选'}</button>`:''}</span></div>${list.length?sortedTransactions(list).map(t=>`<label class="check-row"><input type="checkbox" data-debt="${t.id}" ${selectedDebt.has(t.id)?'checked':''}><span><b>${escapeHtml(t.note||t.category)}</b><small>${t.date} · ${escapeHtml(t.category)}</small></span><b>${money(t.amount)}</b></label>`).join(''):'<div class="empty">🎉 暂无待还款</div>'}</section>`}).join('')||'<section class="panel"><div class="empty">请先在账户页面添加月付方式</div></section>'}<div class="form-actions"><span style="margin-right:auto">已选 ${selectedDebt.size} 笔</span><button class="primary" id="repayBtn" ${selectedDebt.size?'':'disabled'}>一键还款</button></div>`}
function budgetPage(){let total=totalBudget(),spent=expense(),remaining=remainingBudget(),usedPercent=total?spent/total*100:0,remainingPercent=total?Math.max(0,remaining)/total*100:0,barPercent=Math.min(100,usedPercent);return `${head('类别预算','预算按自定义记账周期计算，每笔花销都会扣减对应类别的剩余预算')}<section class="budget-overview"><div class="budget-overview-values"><span><small>总预算</small><b>${money(total)}</b></span><span><small>已用</small><b>${money(spent)}</b></span><span class="${remaining<0?'budget-over':''}"><small>剩余</small><b>${money(remaining)}</b></span></div><div class="budget-percent-row"><span>已用 ${usedPercent.toFixed(1)}%</span><span>剩余 ${remainingPercent.toFixed(1)}%</span></div><div class="budget-progress" role="progressbar" aria-label="本周期预算已用比例" aria-valuemin="0" aria-valuemax="100" aria-valuenow="${Math.min(100,Math.max(0,usedPercent)).toFixed(1)}"><i class="${usedPercent>100?'over':usedPercent>80?'warn':''}" style="width:${barPercent}%"></i></div></section><section class="panel"><div class="panel-title"><span>📊 ${monthLabel()}预算与类别</span><span>拖动手柄可调整顺序</span></div><div class="panel-body"><form id="categoriesForm"><div class="account-list" id="categoryList">${state.categories.map(c=>{let left=Number(state.budgets[c])-used(c);return `<div class="account manage-row sortable-row category-manage-row" data-sort-category="${escapeHtml(c)}"><span class="manage-name"><span class="drag-handle" title="拖动排序">☰</span><input class="emoji-input" data-category-icon="${escapeHtml(c)}" value="${escapeHtml(categoryIcon(c))}" maxlength="8" aria-label="${escapeHtml(c)}图标"><input data-category-name="${escapeHtml(c)}" value="${escapeHtml(c)}" maxlength="12" aria-label="类别名称"></span><small class="${left<0?'budget-over':''}">已用 ${money(used(c))}</small><span class="balance-input"><span>¥</span><input data-budget="${escapeHtml(c)}" type="number" min="0" step="1" value="${state.budgets[c]}" aria-label="${escapeHtml(c)}预算"></span><button type="button" class="icon-button danger-icon" data-remove-category="${escapeHtml(c)}" title="删除类别">×</button></div>`}).join('')}</div><div class="inline-add category-add"><input id="newCategoryIcon" class="emoji-input" maxlength="8" value="📁" aria-label="新类别图标"><input id="newCategory" maxlength="12" placeholder="新类别名称"><button type="button" class="secondary" id="addCategory">＋ 添加类别</button></div><div class="form-actions"><button type="button" class="primary" id="saveCategories">保存类别与预算</button></div></form></div></section>`}
function accountsPage(){let total=Object.values(state.accounts).reduce((a,b)=>a+b,0),history=state.savingsTransfers.slice(0,8);return `${head('账户与支付方式','管理账户余额、月付方式和存款结转')}<div class="cards"><div class="card"><span class="label">账户总余额</span><div class="money">${money(total)}</div></div><div class="card green"><span class="label">存款余额</span><div class="money">${money(state.savings)}</div></div><div class="card orange"><span class="label">本月结余</span><div class="money">${money(income()-expense())}</div></div><div class="card red"><span class="label">待还负债</span><div class="money">${money(debt().reduce((s,t)=>s+t.amount,0))}</div></div></div><div class="savings-actions"><button class="primary" id="depositSavings">💰 月度结余转存</button><button class="secondary" id="withdrawSavings" ${state.savings>0?'':'disabled'}>↩ 从存款提取</button><button class="secondary" id="editSavings">✎ 修改存款余额</button><span>所有转入、提取和余额修改都需要你确认。</span></div><section class="panel"><div class="panel-title"><span>💳 支付平台 / 入账账户</span><span>拖动手柄可调整顺序</span></div><div class="panel-body"><form id="accountsForm"><div class="account-list" id="platformList">${state.platforms.map(p=>`<div class="account manage-row sortable-row" data-sort-platform="${escapeHtml(p.name)}"><span class="manage-name"><span class="drag-handle" title="拖动排序">☰</span><input data-platform-name="${escapeHtml(p.name)}" value="${escapeHtml(p.name)}" maxlength="16" aria-label="支付方式名称"></span><select data-platform-kind="${escapeHtml(p.name)}" aria-label="${escapeHtml(p.name)}类型"><option value="account" ${p.kind==='account'?'selected':''}>余额账户</option><option value="credit" ${p.kind==='credit'?'selected':''}>月付方式</option></select>${p.kind==='account'?`<span class="balance-input"><span>¥</span><input data-account="${escapeHtml(p.name)}" aria-label="${escapeHtml(p.name)}余额" type="number" step="0.01" value="${Number(state.accounts[p.name]||0).toFixed(2)}" required></span>`:'<span class="status-pill">消费后待还款</span>'}<button type="button" class="icon-button danger-icon" data-remove-platform="${escapeHtml(p.name)}" title="删除支付方式">×</button></div>`).join('')}</div><div class="inline-add"><input id="newPlatform" maxlength="16" placeholder="新支付方式名称"><select id="newPlatformKind"><option value="account">余额账户</option><option value="credit">月付方式</option></select><button type="button" class="secondary" id="addPlatform">＋ 添加</button></div><div class="notice" style="margin-top:14px">💡 余额账户会随收支、还款和存款转账增减；月付消费会进入待还款。</div><div class="form-actions"><button class="primary">保存支付方式</button></div></form></div></section><section class="panel savings-history"><div class="panel-title"><span>📒 存款流水</span><span>最近 ${history.length} 笔</span></div><div class="panel-body">${history.length?history.map(t=>{let meta=savingMeta(t);return `<div class="saving-row"><span>${meta.icon}</span><span><b>${meta.label}</b><small>${t.month?`${monthName(t.month)}结转 · `:''}${escapeHtml(t.account||'手动调整')} · ${t.date}</small></span><b class="${meta.className}">${meta.sign}${money(t.amount)}</b></div>`}).join(''):'<div class="empty">还没有存款转账记录</div>'}</div></section>`}
function profilePage(){return `${head('个人资料','设置在账本中显示的用户名和头像')}<div class="settings-shortcuts"><button class="secondary" data-page="stats">📈 查看收支统计</button><button class="secondary" data-page="budget">📊 管理类别与预算</button><button class="secondary" data-page="accounts">💳 管理支付方式</button></div><section class="panel"><div class="panel-title">👤 我的名片</div><div class="panel-body"><form id="profileForm"><div class="profile-editor"><div class="avatar-picker">${avatarHtml('avatar avatar-large')}<label class="secondary upload-button" for="avatarInput">📷 从相册选择</label><input id="avatarInput" type="file" accept="image/jpeg,image/png,image/webp,image/heic,image/heif" hidden><button type="button" class="secondary ${state.profile.avatar?'':'hidden'}" id="removeAvatar">恢复默认头像</button><small>支持 JPG、PNG、WebP 和 iPhone 相册图片，建议小于 5MB</small></div><div class="field"><label for="profileName">用户名</label><input id="profileName" maxlength="20" value="${escapeHtml(state.profile.name)}" placeholder="请输入用户名" required><small>最多 20 个字符</small></div></div><div class="form-actions"><button class="primary">保存个人资料</button></div></form></div></section>`}
function settingsPage(){let skin=state.profile.skin||'vintage1';return `${head('设置','管理个人资料、账本和界面显示')}<div class="settings-stack"><section class="panel settings-profile-panel"><div class="panel-title">⚙ 设置中心</div><div class="panel-body settings-profile-row">${avatarHtml('avatar avatar-large')}<div><h2>${escapeHtml(state.profile.name)}</h2><p>个人资料</p></div><button class="secondary" data-page="profile">✎ 编辑个人资料</button></div></section><form id="settingsForm" class="settings-page-form"><section class="panel mobile-settings-tools"><div class="panel-title">📒 账本管理</div><div class="panel-body mobile-settings-actions"><button type="button" class="secondary" data-page="budget"><span>📊</span><b>类别与预算</b><small>管理消费类别和周期预算</small></button><button type="button" class="secondary" data-page="accounts"><span>💳</span><b>账户与支付方式</b><small>管理余额账户和月付方式</small></button></div></section><section class="panel settings-module-panel"><div class="panel-title">📅 记账周期</div><div class="panel-body settings-module-body"><div class="settings-section-title"><b>自定义周期开始日</b><small>首页、预算、明细和按月统计都会按此周期汇总</small></div><div class="field reminder-date-field"><span class="day-input"><span>每月</span><input id="ledgerCycleStartDay" type="number" min="1" max="31" step="1" value="${state.profile.ledgerCycleStartDay}" aria-label="记账周期开始日" required><span>日开始</span></span><small>当前周期：${cycleLabel(currentCycleMonth())}；当月没有该日期时按最后一天开始</small></div></div></section><section class="panel settings-module-panel"><div class="panel-title">⏰ 还款日期</div><div class="panel-body settings-module-body"><div class="settings-section-title"><b>还款日期提醒</b><small>设置每月还款日，并同步计算下次还款日期</small></div><div class="field reminder-date-field"><span class="day-input"><span>每月</span><input id="repaymentReminderDay" type="number" min="1" max="31" step="1" value="${state.profile.repaymentReminderDay}" aria-label="每月还款日" required><span>日</span></span><small>当月没有该日期时，按当月最后一天提醒</small></div></div></section><section class="panel settings-module-panel"><div class="panel-title">🎨 界面皮肤</div><div class="panel-body settings-module-body"><div class="settings-section-title"><b>选择显示风格</b><small>皮肤会立即预览，保存后同步到你的账本</small></div><div class="skin-options"><button type="button" class="skin-option ${skin==='vintage1'?'selected':''}" data-skin-choice="vintage1" aria-pressed="${skin==='vintage1'}"><span class="skin-preview vintage1-preview"><i></i><b></b><em></em></span><span><b>复古1</b><small>蓝色</small></span></button><button type="button" class="skin-option ${skin==='vintage2'?'selected':''}" data-skin-choice="vintage2" aria-pressed="${skin==='vintage2'}"><span class="skin-preview vintage2-preview"><i></i><b></b><em></em></span><span><b>复古2</b><small>灰银色</small></span></button></div><div class="form-actions"><button type="button" class="primary" id="saveSettings">保存设置</button></div></div></section></form></div>`}
function platformOptions(kind,selected){return state.platforms.filter(p=>p.kind===kind).map(p=>`<option value="${escapeHtml(p.name)}" ${selected===p.name?'selected':''}>${escapeHtml(p.name)}</option>`).join('')}
function transactionForm(t){let editing=!!t,type=t?.type||'expense',mode=platformKind(t?.platform||'');return `<form id="editTxForm"><div class="choice" id="editTypeChoice"><button type="button" data-value="expense" class="${type==='expense'?'selected':''}">花销</button><button type="button" data-value="income" class="${type==='income'?'selected':''}">收入</button></div><div class="form-grid" style="margin-top:14px"><div class="field full"><label>金额</label><input id="editAmount" type="number" min="0.01" step="0.01" value="${editing?t.amount:''}" required></div><div class="field full" id="editCatField"><label>类别</label><select id="editCategory">${state.categories.map(c=>`<option value="${escapeHtml(c)}" ${t?.category===c?'selected':''}>${escapeHtml(c)}</option>`).join('')}</select></div><div class="field"><label>日期</label><input id="editDate" type="date" value="${t?.date||today()}" required></div><div class="field"><label>时间</label><input id="editTime" type="time" value="${t?.time||new Date().toTimeString().slice(0,5)}" required></div><div class="field full" id="editPayModeField"><label>付款方式</label><select id="editPayMode"><option value="account" ${mode==='account'?'selected':''}>余额支付</option><option value="credit" ${mode==='credit'?'selected':''} ${creditPlatforms().length?'':'disabled'}>月付</option></select></div><div class="field full ${mode==='credit'?'hidden':''}" id="editAccountField"><label id="editAccountLabel">支付平台</label><select id="editAccount">${platformOptions('account',t?.platform)}</select></div><div class="field full ${mode==='credit'?'':'hidden'}" id="editCreditField"><label>选择月付平台</label><select id="editCredit">${platformOptions('credit',t?.platform)}</select></div><div class="field full"><label>备注</label><textarea id="editNote" rows="3">${escapeHtml(t?.note||'')}</textarea></div></div><div class="form-actions"><button type="button" class="secondary" id="cancelModal">取消</button><button class="primary">保存修改</button></div></form>`}
function exportStatus(t){if(t.type==='income')return '已入账';if(platformKind(t.platform)==='credit')return t.repaid?'已还款':'待还款';return '已支付'}
function exportSource(t){if(t.source==='wechat')return '微信导入';if(t.source==='alipay')return '支付宝导入';return '手动记录'}
function exportLedgerFile(scope,start,end){if(!globalThis.XLSX){toast('Excel 组件未加载，请刷新页面后重试');return}let range=scope==='cycle'?cycleRange(currentCycleMonth()):scope==='custom'?{start,end}:null,list=sortedTransactions(state.transactions).reverse().filter(t=>!range||t.date>=range.start&&t.date<=range.end);if(!list.length){toast('所选范围没有可导出的收支记录');return}let incomeTotal=list.filter(t=>t.type==='income').reduce((sum,t)=>sum+Number(t.amount),0),expenseTotal=list.filter(t=>t.type==='expense').reduce((sum,t)=>sum+Number(t.amount),0),period=range?`${range.start} 至 ${range.end}`:'全部记录',detailRows=[['日期','时间','类型','分类','金额','支付方式','付款状态','备注','数据来源','导入订单号'],...list.map(t=>[new Date(`${t.date}T00:00:00`),t.time||'',t.type==='income'?'收入':'支出',t.category||'',Number(t.amount),t.platform||'',exportStatus(t),t.note||'',exportSource(t),t.sourceId||''])],summaryRows=[['小金库账单汇总',''],['导出范围',period],['记录数量',list.length],['收入合计',incomeTotal],['支出合计',expenseTotal],['结余',incomeTotal-expenseTotal],['导出时间',new Date()]],detail=XLSX.utils.aoa_to_sheet(detailRows,{cellDates:true}),summary=XLSX.utils.aoa_to_sheet(summaryRows,{cellDates:true});detail['!cols']=[{wch:12},{wch:8},{wch:8},{wch:12},{wch:14},{wch:14},{wch:12},{wch:42},{wch:14},{wch:30}];detail['!autofilter']={ref:`A1:J${detailRows.length}`};summary['!cols']=[{wch:16},{wch:28}];for(let row=2;row<=detailRows.length;row++){if(detail[`A${row}`])detail[`A${row}`].z='yyyy-mm-dd';if(detail[`E${row}`])detail[`E${row}`].z='¥#,##0.00'}['B4','B5','B6'].forEach(cell=>{if(summary[cell])summary[cell].z='¥#,##0.00'});if(summary.B7)summary.B7.z='yyyy-mm-dd hh:mm';let workbook=XLSX.utils.book_new();workbook.Workbook={CalcPr:{calcMode:'auto'}};XLSX.utils.book_append_sheet(workbook,summary,'账单汇总');XLSX.utils.book_append_sheet(workbook,detail,'收支明细');let suffix=range?`${range.start.replaceAll('-','')}-${range.end.replaceAll('-','')}`:'全部';XLSX.writeFile(workbook,`小金库账单_${suffix}.xlsx`,{compression:true,cellDates:true});toast(`已导出 ${list.length} 笔收支记录 ✓`)}
function modalHtml(){if(modal==='export'){let range=cycleRange(currentCycleMonth());return `<div class="modal-wrap"><div class="modal export-modal"><div class="titlebar"><span>📤 导出小金库账单</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><form id="exportLedgerForm"><div class="field"><label for="exportScope">导出范围</label><select id="exportScope"><option value="all">全部收支记录</option><option value="cycle">当前记账周期</option><option value="custom">自定义日期范围</option></select></div><div class="notice" id="exportCycleHint">当前周期：${cycleLabel(currentCycleMonth())}</div><div class="form-grid export-custom-range hidden" id="exportCustomRange"><div class="field"><label for="exportStart">开始日期</label><input id="exportStart" type="date" value="${range.start}"></div><div class="field"><label for="exportEnd">结束日期</label><input id="exportEnd" type="date" value="${range.end}"></div></div><div class="notice">Excel 包含“账单汇总”和“收支明细”两个工作表，仅导出账本数据，不包含账户余额、头像或登录信息。</div><div class="form-actions"><button type="button" class="secondary" id="cancelModal">取消</button><button class="primary">下载 Excel</button></div></form></div></div></div>`}if(modal==='editSavings')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>✎ 修改存款余额</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><form id="editSavingsForm"><div class="saving-summary">当前存款余额 ${money(state.savings)}</div><div class="field"><label for="editSavingsAmount">新的存款余额</label><input id="editSavingsAmount" type="number" min="0" step="0.01" value="${state.savings}" required></div><div class="notice">这是余额校准，不会改变微信、支付宝或银行卡余额。修改后会记录一笔调整流水。</div><div class="form-actions"><button type="button" class="secondary" id="cancelModal">取消</button><button class="primary">确认修改</button></div></form></div></div></div>`;if(modal==='depositSavings'){let month=previousMonth(),summary=monthlyFinance(month);return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>💰 确认月度结余转存</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><form id="depositForm"><div class="field"><label for="depositMonth">结算月份</label><input id="depositMonth" type="month" max="${previousMonth()}" value="${month}" required></div><div class="saving-summary" id="depositSummary">${monthName(month)}结余 ${money(summary.net)} · 还可转存 ${money(availableToSave(month))}</div><div class="field"><label for="depositAccount">从哪个账户扣款</label><select id="depositAccount" required>${platformOptions('account')}</select></div><div class="field"><label for="depositAmount">确认转存金额</label><input id="depositAmount" type="number" min="0.01" step="0.01" placeholder="0.00" required></div><div class="notice">转存不是花销：确认后只会从所选账户扣除，并增加存款余额。</div><div class="form-actions"><button type="button" class="secondary" id="cancelModal">取消</button><button class="primary" ${accountPlatforms().length?'':'disabled'}>确认转入存款</button></div></form></div></div></div>`}if(modal==='withdrawSavings')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>↩ 确认提取存款</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><form id="withdrawForm"><div class="saving-summary">当前存款余额 ${money(state.savings)}</div><div class="field"><label for="withdrawAccount">提取到哪个账户</label><select id="withdrawAccount" required>${platformOptions('account')}</select></div><div class="field"><label for="withdrawAmount">确认提取金额</label><input id="withdrawAmount" type="number" min="0.01" max="${state.savings}" step="0.01" placeholder="0.00" required></div><div class="notice">确认后，存款余额会减少，所选账户余额会增加。</div><div class="form-actions"><button type="button" class="secondary" id="cancelModal">取消</button><button class="primary" ${accountPlatforms().length&&state.savings>0?'':'disabled'}>确认提取</button></div></form></div></div></div>`;if(modal==='repay')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>💳 确认还款</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><p>选择扣款账户：</p><div class="choice" id="repayAccount">${accountPlatforms().map((p,i)=>`<button data-value="${escapeHtml(p.name)}" class="${i===0?'selected':''}">${escapeHtml(p.name)} · ${money(state.accounts[p.name]||0)}</button>`).join('')}</div><div class="form-actions"><button class="secondary" id="cancelModal">取消</button><button class="primary" id="confirmRepay" ${accountPlatforms().length?'':'disabled'}>确认还款</button></div></div></div></div>`;if(modal?.type==='edit')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>✎ 编辑记录</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body">${transactionForm(state.transactions.find(t=>t.id===modal.id))}</div></div></div>`;if(modal?.type==='delete')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>⚠ 删除记录</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><p>确定删除这笔记录吗？相关账户余额会同步还原。</p><div class="form-actions"><button class="secondary" id="cancelModal">取消</button><button class="danger" id="confirmDelete">删除记录</button></div></div></div></div>`;return ''}

function render(){let skin=logged?(state.profile.skin||'vintage1'):'vintage1';document.body.dataset.skin=skin;document.body.dataset.page=logged?page:'login';document.body.dataset.layout=logged?'app':'login';document.querySelector('meta[name="theme-color"]')?.setAttribute('content',skin==='vintage2'?'#174991':'#245edb');if(!logged)return login();app.innerHTML=shell();bind()}
function selectIn(container,cb){document.querySelectorAll(`${container} button`).forEach(b=>b.onclick=()=>{document.querySelectorAll(`${container} button`).forEach(x=>x.classList.remove('selected'));b.classList.add('selected');cb?.(b.dataset.value)})}
function submitTransaction(e){e.preventDefault();let type=document.querySelector('#typeChoice .selected')?.dataset.value||'expense',payMode=document.querySelector('#payModeChoice .selected')?.dataset.value||'account',amount=Number(document.querySelector('#amount').value),selectedPlatform=document.querySelector(type==='income'||payMode==='account'?'#accountPlatformChoice .selected':'#creditPlatformChoice .selected'),selectedCategory=document.querySelector('#catChoice .selected');if(!Number.isFinite(amount)||amount<=0){toast('请输入正确的金额');return}if(!selectedPlatform||type==='expense'&&!selectedCategory){toast('请先添加可用的类别和支付方式');return}let platform=selectedPlatform.dataset.value,cat=type==='income'?'收入':selectedCategory.dataset.value,repaid=platformKind(platform)==='account',t={id:Date.now(),type,amount,category:cat,platform,date:document.querySelector('#date').value,time:document.querySelector('#time').value,note:document.querySelector('#note').value.trim(),repaid};state.transactions.unshift(t);adjustBalance(t,1);save();render();toast('记录已保存 ✓')}
